CROSS JOIN (VALUES
  ('hip_rotation_access_9090_switch_reach', 'Hip Rotation Access 9090 Switch Reach', 'Hip rotation access — 90/90 Hip Switch with Reach.', 162, 2, 'mobilize'),
  ('adductor_rockback_kicking_access', 'Adductor Rockback Kicking Access', 'Adductor range access — Half-Kneeling Adductor Rockback.', 163, 2, 'mobilize'),
  ('wall_supported_hip_cars', 'Wall Supported Hip Cars', 'Hip capsule control — Wall-Supported Hip CARs.', 164, 2, 'mobilize'),
  ('leg_swing_matrix_kicking_prep', 'Leg Swing Matrix Kicking Prep', 'Dynamic kicking range — Leg Swing Matrix.', 165, 2, 'mobilize'),
  ('ankle_dorsiflexion_knee_to_wall', 'Ankle Dorsiflexion Knee To Wall', 'Ankle dorsiflexion access — Ankle Knee-to-Wall Mobilization.', 166, 2, 'mobilize'),
  ('hip_flexor_quad_access_glute_squeeze', 'Hip Flexor Quad Access Glute Squeeze', 'Hip-flexor access and activation — Couch Stretch to Glute Squeeze.', 167, 2, 'mobilize'),
  ('shin_box_get_up_kicking_prep', 'Shin Box Get Up Kicking Prep', 'Ground-to-stance hip integration — Shin Box Get-Up.', 168, 2, 'integrate'),
  ('cossack_shift_reach_adductor_access', 'Cossack Shift Reach Adductor Access', 'Lateral hip and adductor access — Cossack Shift with Reach.', 169, 2, 'mobilize'),
  ('band_hip_flexor_march_kicking_activation', 'Band Hip Flexor March Kicking Activation', 'Hip-flexor activation — Band Hip-Flexor March.', 170, 2, 'activate'),
  ('wall_lean_calf_soleus_pulse', 'Wall Lean Calf Soleus Pulse', 'Lower-leg readiness — Wall Lean Calf-Soleus Pulse.', 171, 2, 'activate')
) AS v(key, name, description, order_index, freshness_sensitivity, subrole_key)
WHERE sp.key = 'prepare_and_access'
ON CONFLICT (key) DO UPDATE SET
