-- Insert 50 kicking athletes exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('90/90 Hip Switch with Reach', '9090-hip-switch-with-reach', '90/90 Hip Switch with Reach uses hip internal rotation, hip external rotation, thoracic rotation to improve a key kicking-athlete problem: Builds controlled hip internal and external rotation so the athlete can chamber, pivot, and re-chamber without borrowing motion from the knee or low back.', 'BEGINNER', 8, 2, 5, 45, 15, 60, '90/90 Hip Switch with Reach is a Prepare & Access exercise for kicking athletes that trains hip rotation access with direct carryover to roundhouse chamber, side-kick chamber, soccer striking hip rotation.', 'Primary subrole: mobilize. Coach this as Prepare & Access work: preserve the intended phase, dose the drill by quality, and connect every rep to support-leg control, hip action, trunk transfer, and safe reset behavior.', 'Rotate the hip, not the low back.', 'Hip rotation access', 'prepare_and_access', 'mobilize', 'hip_rotation_access_9090_switch_reach', '{"primary_joint_actions":["hip internal rotation","hip external rotation","thoracic rotation"],"primary_tissues":["deep hip rotators","adductors","obliques"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"low","balance_demand":"low","coordination_demand":"medium","impact_level":0}'::jsonb, '{"movement_description":"Perform 90/90 Hip Switch with Reach with attention to hip internal rotation, hip external rotation, thoracic rotation, then reset into a stance or position that would allow another kick, strike, or ball action.","setup":["Set up with none, mat and enough open space for the athlete to move, pivot, and stop without crowding.","Explain the intended phase and quality gate before the first rep so the athlete knows whether this is access, skill, output, strength, resilience, conditioning, or restore work.","Establish stance foot pressure, rib-pelvis position, and a safe return/reset position before adding speed, load, target, or partner input.","Connect the drill to roundhouse chamber, side-kick chamber so the athlete understands the transfer target without rushing the movement."],"execution_steps":["Move into the start position and establish breathing, foot pressure, and joint alignment.","Perform the rep smoothly through the available range without forcing or rushing.","Return to the start position under control and check that the athlete feels more ready.","Repeat only while the motion gets cleaner rather than more strained."],"coach_cues":["Rotate the hip, not the low back.","Own the support foot.","Ribs and pelvis stay organized.","Reset before the next rep."],"common_faults":["Chasing range or speed before control","Support foot collapsing or twisting","Leaning through the low back","Letting the kick or movement finish in a poor stance"],"breathing_cues":["Exhale to organize the ribs before effort.","Do not hold breath unless specifically bracing for a loaded strength rep.","Recover nasal or calm breathing between quality attempts."],"quality_gate":"A rep counts only if 90/90 Hip Switch with Reach keeps pain-free range, organized breathing, clean support-foot pressure, controlled hip/trunk position, and a safe reset that supports roundhouse chamber, side-kick chamber.","stop_signs":["pain","pinching","numbness","dizziness","loss of balance","unsafe spacing","joint twisting","breath holding"]}'::jsonb),
  ('Half-Kneeling Adductor Rockback', 'half-kneeling-adductor-rockback', 'Half-Kneeling Adductor Rockback uses hip abduction, hip flexion, pelvic control to improve a key kicking-athlete problem: Prepares the groin and inside-leg line for high chambers, lateral kicks, checks, and soccer striking without forcing passive end range.', 'BEGINNER', 8, 2, 5, 45, 15, 60, 'Half-Kneeling Adductor Rockback is a Prepare & Access exercise for kicking athletes that trains adductor range access with direct carryover to high kick prep, inside-of-foot pass, lateral kick recovery.', 'Primary subrole: mobilize. Coach this as Prepare & Access work: preserve the intended phase, dose the drill by quality, and connect every rep to support-leg control, hip action, trunk transfer, and safe reset behavior.', 'Rock from the hip and keep the ribs quiet.', 'Adductor range access', 'prepare_and_access', 'mobilize', 'adductor_rockback_kicking_access', '{"primary_joint_actions":["hip abduction","hip flexion","pelvic control"],"primary_tissues":["adductors","groin connective tissue","medial hamstrings"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"low","balance_demand":"low","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Perform Half-Kneeling Adductor Rockback with attention to hip abduction, hip flexion, pelvic control, then reset into a stance or position that would allow another kick, strike, or ball action.","setup":["Set up with none, mat and enough open space for the athlete to move, pivot, and stop without crowding.","Explain the intended phase and quality gate before the first rep so the athlete knows whether this is access, skill, output, strength, resilience, conditioning, or restore work.","Establish stance foot pressure, rib-pelvis position, and a safe return/reset position before adding speed, load, target, or partner input.","Connect the drill to high kick prep, inside-of-foot pass so the athlete understands the transfer target without rushing the movement."],"execution_steps":["Move into the start position and establish breathing, foot pressure, and joint alignment.","Perform the rep smoothly through the available range without forcing or rushing.","Return to the start position under control and check that the athlete feels more ready.","Repeat only while the motion gets cleaner rather than more strained."],"coach_cues":["Rock from the hip and keep the ribs quiet.","Own the support foot.","Ribs and pelvis stay organized.","Reset before the next rep."],"common_faults":["Chasing range or speed before control","Support foot collapsing or twisting","Leaning through the low back","Letting the kick or movement finish in a poor stance"],"breathing_cues":["Exhale to organize the ribs before effort.","Do not hold breath unless specifically bracing for a loaded strength rep.","Recover nasal or calm breathing between quality attempts."],"quality_gate":"A rep counts only if Half-Kneeling Adductor Rockback keeps pain-free range, organized breathing, clean support-foot pressure, controlled hip/trunk position, and a safe reset that supports high kick prep, inside-of-foot pass.","stop_signs":["pain","pinching","numbness","dizziness","loss of balance","unsafe spacing","joint twisting","breath holding"]}'::jsonb),
  ('Wall-Supported Hip CARs', 'wall-supported-hip-cars', 'Wall-Supported Hip CARs uses hip flexion, hip abduction, hip internal rotation to improve a key kicking-athlete problem: Gives kickers slow ownership of the whole hip circle, exposing sticky ranges before speed, pads, sparring, or ball striking.', 'BEGINNER', 8, 2, 5, 45, 15, 60, 'Wall-Supported Hip CARs is a Prepare & Access exercise for kicking athletes that trains hip capsule control with direct carryover to chamber control, support-leg balance, kick path control.', 'Primary subrole: mobilize. Coach this as Prepare & Access work: preserve the intended phase, dose the drill by quality, and connect every rep to support-leg control, hip action, trunk transfer, and safe reset behavior.', 'Move slowly enough that nothing clicks or cheats.', 'Hip capsule control', 'prepare_and_access', 'mobilize', 'wall_supported_hip_cars', '{"primary_joint_actions":["hip flexion","hip abduction","hip internal rotation","hip extension"],"primary_tissues":["hip capsule","glutes","adductors","hip flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"low","balance_demand":"medium","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Perform Wall-Supported Hip CARs with attention to hip flexion, hip abduction, hip internal rotation, then reset into a stance or position that would allow another kick, strike, or ball action.","setup":["Set up with wall and enough open space for the athlete to move, pivot, and stop without crowding.","Explain the intended phase and quality gate before the first rep so the athlete knows whether this is access, skill, output, strength, resilience, conditioning, or restore work.","Establish stance foot pressure, rib-pelvis position, and a safe return/reset position before adding speed, load, target, or partner input.","Connect the drill to chamber control, support-leg balance so the athlete understands the transfer target without rushing the movement."],"execution_steps":["Move into the start position and establish breathing, foot pressure, and joint alignment.","Perform the rep smoothly through the available range without forcing or rushing.","Return to the start position under control and check that the athlete feels more ready.","Repeat only while the motion gets cleaner rather than more strained."],"coach_cues":["Move slowly enough that nothing clicks or cheats.","Own the support foot.","Ribs and pelvis stay organized.","Reset before the next rep."],"common_faults":["Chasing range or speed before control","Support foot collapsing or twisting","Leaning through the low back","Letting the kick or movement finish in a poor stance"],"breathing_cues":["Exhale to organize the ribs before effort.","Do not hold breath unless specifically bracing for a loaded strength rep.","Recover nasal or calm breathing between quality attempts."],"quality_gate":"A rep counts only if Wall-Supported Hip CARs keeps pain-free range, organized breathing, clean support-foot pressure, controlled hip/trunk position, and a safe reset that supports chamber control, support-leg balance.","stop_signs":["pain","pinching","numbness","dizziness","loss of balance","unsafe spacing","joint twisting","breath holding"]}'::jsonb),
