  ('Repeat Kick Interval', 'repeat-kick-interval', 'Repeat Kick Interval uses hip flexion, hip rotation, support-foot pivot to improve a key kicking-athlete problem: Builds the ability to repeat technically useful kicks under fatigue while preserving recoil, stance, and defensive readiness.', 'BEGINNER', 8, 4, 10, 20, 50, 70, 'Repeat Kick Interval is a Sustained Capacity exercise for kicking athletes that trains kick repeatability conditioning with direct carryover to kickboxing rounds, MMA kick volume, late-game soccer kicking.', 'Primary subrole: conditioning_intervals. Coach this as Sustained Capacity work: preserve the intended phase, dose the drill by quality, and connect every rep to support-leg control, hip action, trunk transfer, and safe reset behavior.', 'Every kick must still come home.', 'Kick repeatability conditioning', 'sustained_capacity', 'conditioning_intervals', 'repeat_kick_interval_quality_gate', '{"primary_joint_actions":["hip flexion","hip rotation","support-foot pivot","recoil"],"primary_tissues":["hip flexors","calves","glutes","quadriceps"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"medium","balance_demand":"medium","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Perform Repeat Kick Interval with attention to hip flexion, hip rotation, support-foot pivot, then reset into a stance or position that would allow another kick, strike, or ball action.","setup":["Set up with pads, partner, timer and enough open space for the athlete to move, pivot, and stop without crowding.","Explain the intended phase and quality gate before the first rep so the athlete knows whether this is access, skill, output, strength, resilience, conditioning, or restore work.","Establish stance foot pressure, rib-pelvis position, and a safe return/reset position before adding speed, load, target, or partner input.","Connect the drill to kickboxing rounds, MMA kick volume so the athlete understands the transfer target without rushing the movement."],"execution_steps":["Begin each interval from an athletic stance with a clear start cue and defined finish/reset area.","Move with useful sport intent while keeping kick mechanics, footwork, posture, and spacing under control.","Use the rest period to recover enough that the next interval still looks like training, not survival.","Stop the block when output, recoil, braking, or technical accuracy drops below the quality gate."],"coach_cues":["Every kick must still come home.","Own the support foot.","Ribs and pelvis stay organized.","Reset before the next rep."],"common_faults":["Chasing range or speed before control","Support foot collapsing or twisting","Leaning through the low back","Letting the kick or movement finish in a poor stance"],"breathing_cues":["Exhale to organize the ribs before effort.","Do not hold breath unless specifically bracing for a loaded strength rep.","Recover nasal or calm breathing between quality attempts."],"quality_gate":"A rep counts only if Repeat Kick Interval keeps pain-free range, organized breathing, clean support-foot pressure, controlled hip/trunk position, and a safe reset that supports kickboxing rounds, MMA kick volume.","stop_signs":["pain","pinching","numbness","dizziness","loss of balance","unsafe spacing","joint twisting","breath holding","visible speed drop","sloppy recoil","loud uncontrolled landing","target accuracy collapse","unclear partner role","surprise contact","communication failure"]}'::jsonb),
  ('Shuttle-to-Kick Conditioning', 'shuttle-to-kick-conditioning', 'Shuttle-to-Kick Conditioning uses acceleration, deceleration, support-foot pivot to improve a key kicking-athlete problem: Conditions the sport sequence of moving, braking, striking, and recovering without pretending that tired sloppy kicks are better training.', 'BEGINNER', 8, 4, 10, 20, 50, 70, 'Shuttle-to-Kick Conditioning is a Sustained Capacity exercise for kicking athletes that trains footwork-to-kick repeatability with direct carryover to MMA cage pressure, kickboxing combinations, soccer transition strike.', 'Primary subrole: conditioning_intervals. Coach this as Sustained Capacity work: preserve the intended phase, dose the drill by quality, and connect every rep to support-leg control, hip action, trunk transfer, and safe reset behavior.', 'Brake, kick, reset, then go again.', 'Footwork-to-kick repeatability', 'sustained_capacity', 'conditioning_intervals', 'shuttle_to_kick_conditioning', '{"primary_joint_actions":["acceleration","deceleration","support-foot pivot","hip flexion"],"primary_tissues":["calves","quadriceps","glutes","hip flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"medium","balance_demand":"medium","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Perform Shuttle-to-Kick Conditioning with attention to acceleration, deceleration, support-foot pivot, then reset into a stance or position that would allow another kick, strike, or ball action.","setup":["Set up with cones, pads, partner, timer and enough open space for the athlete to move, pivot, and stop without crowding.","Explain the intended phase and quality gate before the first rep so the athlete knows whether this is access, skill, output, strength, resilience, conditioning, or restore work.","Establish stance foot pressure, rib-pelvis position, and a safe return/reset position before adding speed, load, target, or partner input.","Connect the drill to MMA cage pressure, kickboxing combinations so the athlete understands the transfer target without rushing the movement."],"execution_steps":["Begin each interval from an athletic stance with a clear start cue and defined finish/reset area.","Move with useful sport intent while keeping kick mechanics, footwork, posture, and spacing under control.","Use the rest period to recover enough that the next interval still looks like training, not survival.","Stop the block when output, recoil, braking, or technical accuracy drops below the quality gate."],"coach_cues":["Brake, kick, reset, then go again.","Own the support foot.","Ribs and pelvis stay organized.","Reset before the next rep."],"common_faults":["Chasing range or speed before control","Support foot collapsing or twisting","Leaning through the low back","Letting the kick or movement finish in a poor stance"],"breathing_cues":["Exhale to organize the ribs before effort.","Do not hold breath unless specifically bracing for a loaded strength rep.","Recover nasal or calm breathing between quality attempts."],"quality_gate":"A rep counts only if Shuttle-to-Kick Conditioning keeps pain-free range, organized breathing, clean support-foot pressure, controlled hip/trunk position, and a safe reset that supports MMA cage pressure, kickboxing combinations.","stop_signs":["pain","pinching","numbness","dizziness","loss of balance","unsafe spacing","joint twisting","breath holding","visible speed drop","sloppy recoil","loud uncontrolled landing","target accuracy collapse","unclear partner role","surprise contact","communication failure"]}'::jsonb),
  ('90/90 Breathing with Hip Reset', '9090-breathing-with-hip-reset', '90/90 Breathing with Hip Reset uses hip flexion support, pelvic repositioning, rib expansion to improve a key kicking-athlete problem: Downshifts the athlete after kicking volume and helps recover hip, pelvis, and rib position without adding more training stress.', 'BEGINNER', 8, 1, 5, 60, 0, 75, '90/90 Breathing with Hip Reset is a Restore exercise for kicking athletes that trains cooldown hip and nervous-system reset with direct carryover to post-kicking recovery, low-readiness reset, restore phase.', 'Primary subrole: breathing_downshift. Coach this as Restore work: preserve the intended phase, dose the drill by quality, and connect every rep to support-leg control, hip action, trunk transfer, and safe reset behavior.', 'Exhale long, let the ribs drop, and leave the hips calmer.', 'Cooldown hip and nervous-system reset', 'restore', 'breathing_downshift', '9090_breathing_hip_reset_kickers', '{"primary_joint_actions":["hip flexion support","pelvic repositioning","rib expansion"],"primary_tissues":["diaphragm","hip flexors","low back tissues"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"low","balance_demand":"low","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Perform 90/90 Breathing with Hip Reset with attention to hip flexion support, pelvic repositioning, rib expansion, then reset into a stance or position that would allow another kick, strike, or ball action.","setup":["Set up with mat, wall and enough open space for the athlete to move, pivot, and stop without crowding.","Explain the intended phase and quality gate before the first rep so the athlete knows whether this is access, skill, output, strength, resilience, conditioning, or restore work.","Establish stance foot pressure, rib-pelvis position, and a safe return/reset position before adding speed, load, target, or partner input.","Connect the drill to post-kicking recovery, low-readiness reset so the athlete understands the transfer target without rushing the movement."],"execution_steps":["Move into the supported position slowly and find a calm, pain-free range.","Use long exhales and relaxed inhales while keeping the hips, ribs, and jaw quiet.","Allow the target tissues to reduce tone without forcing extra range.","Exit the position slowly and check that the athlete feels calmer or less guarded."],"coach_cues":["Exhale long, let the ribs drop, and leave the hips calmer.","Own the support foot.","Ribs and pelvis stay organized.","Reset before the next rep."],"common_faults":["Chasing range or speed before control","Support foot collapsing or twisting","Leaning through the low back","Letting the kick or movement finish in a poor stance"],"breathing_cues":["Exhale to organize the ribs before effort.","Do not hold breath unless specifically bracing for a loaded strength rep.","Recover nasal or calm breathing between quality attempts."],"quality_gate":"A rep counts only if 90/90 Breathing with Hip Reset keeps pain-free range, organized breathing, clean support-foot pressure, controlled hip/trunk position, and a safe reset that supports post-kicking recovery, low-readiness reset.","stop_signs":["pain","pinching","numbness","dizziness","loss of balance","unsafe spacing","joint twisting","breath holding"]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

