INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, COALESCE(m.fit_weight, 5), 'primary', m.slot, pos.order_index,
  COALESCE(m.freshness_required, FALSE), COALESCE(m.fatigue_sensitivity, 2), COALESCE(m.fatigue_cost, 2),
  COALESCE(m.technical_complexity, 2), COALESCE(m.impact_level, 1), COALESCE(m.intensity_ceiling, 'moderate')
FROM (VALUES
  ('9090-hip-switch-with-reach', 'prepare_and_access', 'hip_rotation_access_9090_switch_reach', 5, FALSE, 1, 1, 3, 0, 'low'),
  ('half-kneeling-adductor-rockback', 'prepare_and_access', 'adductor_rockback_kicking_access', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('wall-supported-hip-cars', 'prepare_and_access', 'wall_supported_hip_cars', 5, FALSE, 1, 1, 4, 0, 'low'),
  ('leg-swing-matrix', 'prepare_and_access', 'leg_swing_matrix_kicking_prep', 5, FALSE, 1, 1, 3, 1, 'low'),
  ('ankle-knee-to-wall-mobilization', 'prepare_and_access', 'ankle_dorsiflexion_knee_to_wall', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('couch-stretch-to-glute-squeeze', 'prepare_and_access', 'hip_flexor_quad_access_glute_squeeze', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('shin-box-get-up-kicking', 'prepare_and_access', 'shin_box_get_up_kicking_prep', 5, FALSE, 1, 1, 4, 1, 'low'),
  ('cossack-shift-with-reach', 'prepare_and_access', 'cossack_shift_reach_adductor_access', 5, FALSE, 1, 1, 3, 0, 'low'),
  ('band-hip-flexor-march', 'prepare_and_access', 'band_hip_flexor_march_kicking_activation', 5, FALSE, 1, 1, 3, 0, 'low'),
  ('wall-lean-calf-soleus-pulse', 'prepare_and_access', 'wall_lean_calf_soleus_pulse', 5, FALSE, 1, 1, 3, 1, 'low'),
  ('wall-supported-slow-front-kick-chamber', 'movement_intelligence', 'front_kick_chamber_wall_control', 5, TRUE, 4, 1, 4, 0, 'moderate'),
  ('lateral-chamber-hold-to-re-chamber', 'movement_intelligence', 'lateral_chamber_hold_rechamber', 5, TRUE, 4, 1, 4, 0, 'moderate'),
