  CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
FROM (VALUES
  ('9090-hip-switch-with-reach', 'Use no load, smaller range, fewer choices, and a wall or coach support when needed. Keep 90/90 Hip Switch with Reach controlled and prioritize stance, hip, trunk, and foot position before speed or load. 1-2 light sets; stop before fatigue or frustration.', ''),
  ('half-kneeling-adductor-rockback', 'Use no load, smaller range, fewer choices, and a wall or coach support when needed. Keep Half-Kneeling Adductor Rockback controlled and prioritize stance, hip, trunk, and foot position before speed or load. 1-2 light sets; stop before fatigue or frustration.', ''),
  ('wall-supported-hip-cars', 'Use no load, smaller range, fewer choices, and a wall or coach support when needed. Keep Wall-Supported Hip CARs controlled and prioritize stance, hip, trunk, and foot position before speed or load. 1-2 light sets; stop before fatigue or frustration.', ''),
  ('leg-swing-matrix', 'Use no load, smaller range, fewer choices, and a wall or coach support when needed. Keep Leg Swing Matrix controlled and prioritize stance, hip, trunk, and foot position before speed or load. 1-2 light sets; stop before fatigue or frustration.', ''),
